public boolean findDuplicate(int[] nums) {
    int maxNum = Arrays.stream(nums).max().getAsInt();
    for (int i = 0; i <= maxNum; i++) {
        if (countOccurrences(nums, i) > 1) {
            return true;
        }
    }
    return false;
}
private int countOccurrences(int[] nums, int num) {
    int count = 0;
    for (int i : nums) {
        if (num == i) {
            count++;
        }
    }
    return count;
}}

