class Solution:
    def findDuplicate(self, nums: list[int]) -> int:
        count_map = {}
        for num in nums:
            if num in count_map:
                count_map[num] += 1
            else:
                count_map[num] = 1
        max_count = max(count_map.values())
        max_duplicate = -1
        for num, count in count_map.items():
            if count == max_count:
                max_duplicate = num
                break
        return max_duplicate

