class Solution {
public:
    int findDuplicate(vector<int>& nums) {
        map<int, int> count_map;
        for (int num : nums) {
            count_map[num]++;
        }
        int max_count = 0;
        int max_duplicate = -1;
        for (auto& [num, count] : count_map) {
            if (count > max_count) {
                max_count = count;
                max_duplicate = num;
            }
        }
        return max_duplicate;
    }
};
